import React from 'react';
import { Link } from 'react-router-dom';
import './style.css';

const TodoItem = ({ id, title, completed, onClick }) => {
  return (
    <div className={`todo-item ${completed ? 'todo-item-completed' : ''}`}>
      <Link to={`/todo/${id}`} onClick={onClick} className="todo-item-link">
        <p className="todo-item-status">
          {completed ? 'Completed' : 'Not Completed'}
        </p>
        <h3 className="todo-item-title">{title}</h3>
      </Link>
    </div>
  );
};

export default TodoItem;
